INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1506, 195980, 6, 1238, '大家小心了', '最新呼吸道传染病，各位小心！
<br>最近在广东省，特别是在珠江三角洲地区，流行一种不明原因的肺炎，病情发展凶险，已经有多人发病，小部分病人已经死亡，据悉，广州市卫生局到今日已经发现共有超过100例发病，其中医护人员发病率达44%。此病症最早发现于广东省珠江三角洲的城市中山、顺德、河源等地，后因当地医院无法控制病情转院到广州各大医院。深圳也有不少的病历报道，请各位网友近期不要到上述城市旅游，避免长时间到公众场所停留，看好自己家中的老人以及儿童，这些人群自身免疫力较差，发病后有重症倾向。 
<br>
<br>此病的主要特征：1、症状：一周左右不明原因高热，体温通常在40度左右，后过渡为无明显原因的进行性的呼吸困难，拌或不拌有咳嗽、咳痰、流涕等呼吸道疾病症状。2、体征：发病初期双肺并无发现任何阳性体征，无干湿罗音（肺部感染通常有此类表现），进行性发展或合并有其他类型肺部感染后可有罗音出现。3、实验室检查：通常血常规提示白细胞总数正常或者降低，分叶比例不高或者降低，淋巴比例升高或正常。4、胸片：初期无任何异常表现，随病情发展，双肺可以出现絮状的斑片影或者是虫蚀状影，有间质性肺炎的改变特征，急性进行性发展可见全肺呈实性改变（“白肺”）。5、病原学检查：目前暂时未检测出病原体。6、传播途径：目前发病的人群中医护人员占近半数，发病人员主要为接触患者的首诊医生和护士，转送患者的救护车司机和担架员。从发病病例看，近距离接触者发病多，估计靠飞沫通过空气传染，所以各位同行接近患者一要作好隔离防护措施。在此我要说明的是，潜伏期为4天左右，所有的病例无明显的年龄倾向，目前从1岁到85岁的病例都有，死亡病历大都是免疫力差的人群，而且发病的症状、体征、胸片与病情不平行，很多病历未见任何自觉的异常已经发生了呼吸衰竭，需要上呼吸机辅助通气度过危险期，而且使用现在任何的抗生素无效。 
<br>
<br>治疗原则，因为此不明原因肺炎对抗生素治疗毫无效果，估计为病毒性肺炎。因此治疗主要为支持治疗，即物理降温，补充液体，增强免疫力（注射人体免疫丙种球蛋白，干扰素等），合理使用激素控制炎症发展，合并有其他类型肺炎酌情使用抗生素。预防推荐使用口服红霉素加喹诺酮类抗生素，注意保暖，减少接触发病人群，减少到公众场所，不到发病地区长时间停留。要对各位说明的是，从观察的病例看来，本病从发生是否有重症倾向，与自身免疫力很有关系，重症病人起病数小时内可进行性发展至呼吸衰竭，轻症病人可能只是表现为咳嗽、头痛、喉咙不适等类似感冒的症状。相信进期内国家的卫生防疫机关会检测出病原体，并制出针对疾病的疫苗供公众使用。 
<br>
<br>目前广州市各大医院都有上述的病例，集中限制或转院到广州市第八人民医院，中山大学第三医院，广州市胸科医院和南方医院，广医附一院、中山二院等，以上医院的呼吸科及传染科均有重症病人，目前均维持上呼吸机支持治疗的就地治疗。请大家到医院看病时作好自身防护措施。', '最新呼吸道传染病，各位小心！

